  const tokens: Token[] = [];
  let i = 0;
  const len = expr.length;

  while (i < len) {
    if (expr[i] === " ") {
      i++;
      continue;
    }

    if (expr[i] >= "0" && expr[i] <= "9") {
      let num = "";
      while (i < len && expr[i] >= "0" && expr[i] <= "9") {
        num += expr[i];
        i++;
