      stack.push(token);
    } else if (token.type === "LPAREN") {
      stack.push(token);
    } else if (token.type === "RPAREN") {
      while (stack.length > 0 && stack[stack.length - 1].type !== "LPAREN") {
        output.push(stack.pop()!);
      }
      if (stack.length > 0 && stack[stack.length - 1].type === "LPAREN") {
        stack.pop();
      }
